1	#!/usr/bin/env node
2	/**
3	 * Auto-Tmux Dev Hook - Start dev servers in tmux/cmd automatically
4	 *
5	 * macOS/Linux: Runs dev server in a named tmux session (non-blocking).
6	 *              Falls back to original command if tmux is not installed.
7	 * Windows: Opens dev server in a new cmd window (non-blocking).
8	 *
9	 * Runs before Bash tool use. If command is a dev server (npm run dev, pnpm dev, yarn dev, bun run dev),
10	 * transforms it to run in a detached session.
11	 *
12	 * Benefits:
13	 * - Dev server runs detached (doesn't block Claude Code)
14	 * - Session persists (can run `tmux capture-pane -t <session> -p` to see logs on Unix)
15	 * - Session name matches project directory (allows multiple projects simultaneously)
16	 *
17	 * Session management (Unix):
18	 * - Checks tmux availability before transforming
19	 * - Kills any existing session with the same name (clean restart)
20	 * - Creates new detached session
21	 * - Reports session name and how to view logs
22	 *
23	 * Session management (Windows):
24	 * - Opens new cmd window with descriptive title
25	 * - Allows multiple dev servers to run simultaneously
26	 */
27	
28	const path = require('path');
29	const { spawnSync } = require('child_process');
30	
31	const MAX_STDIN = 1024 * 1024; // 1MB limit
32	let data = '';
33	process.stdin.setEncoding('utf8');
34	
35	process.stdin.on('data', chunk => {
36	  if (data.length < MAX_STDIN) {
37	    const remaining = MAX_STDIN - data.length;
38	    data += chunk.substring(0, remaining);
39	  }
40	});
41	
42	process.stdin.on('end', () => {
43	  let input;
44	  try {
45	    input = JSON.parse(data);
46	    const cmd = input.tool_input?.command || '';
47	
48	    // Detect dev server commands: npm run dev, pnpm dev, yarn dev, bun run dev
49	    // Use word boundary (\b) to avoid matching partial commands
50	    const devServerRegex = /(npm run dev\b|pnpm( run)? dev\b|yarn dev\b|bun run dev\b)/;
51	
52	    if (devServerRegex.test(cmd)) {
53	      // Get session name from current directory basename, sanitize for shell safety
54	      // e.g., /home/user/Portfolio → "Portfolio", /home/user/my-app-v2 → "my-app-v2"
55	      const rawName = path.basename(process.cwd());
56	      // Replace non-alphanumeric characters (except - and _) with underscore to prevent shell injection
57	      const sessionName = rawName.replace(/[^a-zA-Z0-9_-]/g, '_') || 'dev';
58	
59	      if (process.platform === 'win32') {
60	        // Windows: open in a new cmd window (non-blocking)
61	        // Escape double quotes in cmd for cmd /k syntax
62	        const escapedCmd = cmd.replace(/"/g, '""');
63	        input.tool_input.command = `start "DevServer-${sessionName}" cmd /k "${escapedCmd}"`;
64	      } else {
65	        // Unix (macOS/Linux): Check tmux is available before transforming
66	        const tmuxCheck = spawnSync('which', ['tmux'], { encoding: 'utf8' });
67	        if (tmuxCheck.status === 0) {
68	          // Escape single quotes for shell safety: 'text' -> 'text'\''text'
69	          const escapedCmd = cmd.replace(/'/g, "'\\''");
70	
71	          // Build the transformed command:
72	          // 1. Kill existing session (silent if doesn't exist)
73	          // 2. Create new detached session with the dev command
74	          // 3. Echo confirmation message with instructions for viewing logs
75	          const transformedCmd = `SESSION="${sessionName}"; tmux kill-session -t "$SESSION" 2>/dev/null || true; tmux new-session -d -s "$SESSION" '${escapedCmd}' && echo "[Hook] Dev server started in tmux session '${sessionName}'. View logs: tmux capture-pane -t ${sessionName} -p -S -100"`;
76	
77	          input.tool_input.command = transformedCmd;
78	        }
79	        // else: tmux not found, pass through original command unchanged
80	      }
81	    }
82	    process.stdout.write(JSON.stringify(input));
83	  } catch {
84	    // Invalid input — pass through original data unchanged
85	    process.stdout.write(data);
86	  }
87	  process.exit(0);
88	});
